#include "particle.h"

// Initialize particles with random positions and zero velocities/forces
void initialize_particles(Particle *particles, int n) {
    srand(42); // Fixed seed for reproducibility

    for (int i = 0; i < n; i++) {
        particles[i].x = ((double)rand() / RAND_MAX) * DOMAIN_SIZE;
        particles[i].y = ((double)rand() / RAND_MAX) * DOMAIN_SIZE;
        particles[i].vx = 0.0;
        particles[i].vy = 0.0;
        particles[i].fx = 0.0;
        particles[i].fy = 0.0;
    }
}

// Compute forces between particles using spatial binning for O(n) complexity
void compute_forces_serial(Particle *particles, int n) {
    // Reset forces
    for (int i = 0; i < n; i++) {
        particles[i].fx = 0.0;
        particles[i].fy = 0.0;
    }

    // Simple approach without spatial binning for now
    // In a real implementation, we would use spatial binning for O(n) complexity
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            double dx = particles[j].x - particles[i].x;
            double dy = particles[j].y - particles[i].y;
            double r = sqrt(dx*dx + dy*dy);

            // Only consider interactions within cutoff radius
            if (r < CUTOFF_RADIUS && r > EPSILON) {
                // Simple repulsive force
                double force = 1.0 / (r * r);
                double fx = force * dx / r;
                double fy = force * dy / r;

                particles[i].fx -= fx;
                particles[i].fy -= fy;
                particles[j].fx += fx;
                particles[j].fy += fy;
            }
        }
    }
}

// Update particle positions based on forces
void update_positions(Particle *particles, int n) {
    for (int i = 0; i < n; i++) {
        // Update velocity
        particles[i].vx += particles[i].fx * TIME_STEP;
        particles[i].vy += particles[i].fy * TIME_STEP;

        // Update position
        particles[i].x += particles[i].vx * TIME_STEP;
        particles[i].y += particles[i].vy * TIME_STEP;

        // Boundary conditions (periodic)
        if (particles[i].x < 0) particles[i].x += DOMAIN_SIZE;
        if (particles[i].x >= DOMAIN_SIZE) particles[i].x -= DOMAIN_SIZE;
        if (particles[i].y < 0) particles[i].y += DOMAIN_SIZE;
        if (particles[i].y >= DOMAIN_SIZE) particles[i].y -= DOMAIN_SIZE;
    }
}

// Calculate minimum distance between any two particles
double calculate_min_distance(Particle *particles, int n) {
    double min_dist = DOMAIN_SIZE;

    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            double dx = particles[j].x - particles[i].x;
            double dy = particles[j].y - particles[i].y;

            // Handle periodic boundary conditions
            if (dx > DOMAIN_SIZE/2) dx -= DOMAIN_SIZE;
            if (dx < -DOMAIN_SIZE/2) dx += DOMAIN_SIZE;
            if (dy > DOMAIN_SIZE/2) dy -= DOMAIN_SIZE;
            if (dy < -DOMAIN_SIZE/2) dy += DOMAIN_SIZE;

            double dist = sqrt(dx*dx + dy*dy);
            if (dist < min_dist && dist > EPSILON) {
                min_dist = dist;
            }
        }
    }

    return min_dist / CUTOFF_RADIUS; // Normalize by cutoff radius
}

// Calculate average distance between particles
double calculate_avg_distance(Particle *particles, int n) {
    double total_dist = 0.0;
    int count = 0;

    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            double dx = particles[j].x - particles[i].x;
            double dy = particles[j].y - particles[i].y;

            // Handle periodic boundary conditions
            if (dx > DOMAIN_SIZE/2) dx -= DOMAIN_SIZE;
            if (dx < -DOMAIN_SIZE/2) dx += DOMAIN_SIZE;
            if (dy > DOMAIN_SIZE/2) dy -= DOMAIN_SIZE;
            if (dy < -DOMAIN_SIZE/2) dy += DOMAIN_SIZE;

            double dist = sqrt(dx*dx + dy*dy);
            if (dist > EPSILON) {
                total_dist += dist;
                count++;
            }
        }
    }

    return (count > 0) ? (total_dist / count) / CUTOFF_RADIUS : 0.0; // Normalize by cutoff radius
}

// Write particle positions to file
void write_positions(FILE *file, Particle *particles, int n) {
    fprintf(file, "%d %.1f\n", n, DOMAIN_SIZE);
    for (int i = 0; i < n; i++) {
        fprintf(file, "%.6f %.6f\n", particles[i].x, particles[i].y);
    }
}
