#include "particle.h"
#include <omp.h>

// Compute forces between particles with OpenMP parallelization
void compute_forces_openmp(Particle *particles, int n, int num_threads) {
    // Reset forces
    #pragma omp parallel for num_threads(num_threads)
    for (int i = 0; i < n; i++) {
        particles[i].fx = 0.0;
        particles[i].fy = 0.0;
    }

    // Compute forces
    #pragma omp parallel for num_threads(num_threads) schedule(static)
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            double dx = particles[j].x - particles[i].x;
            double dy = particles[j].y - particles[i].y;
            double r = sqrt(dx*dx + dy*dy);

            // Only consider interactions within cutoff radius
            if (r < CUTOFF_RADIUS && r > EPSILON) {
                // Simple repulsive force
                double force = 1.0 / (r * r);
                double fx = force * dx / r;
                double fy = force * dy / r;

                #pragma omp atomic
                particles[i].fx -= fx;
                #pragma omp atomic
                particles[i].fy -= fy;
                #pragma omp atomic
                particles[j].fx += fx;
                #pragma omp atomic
                particles[j].fy += fy;
            }
        }
    }
}

int main(int argc, char *argv[]) {
    int n = 0;  // Number of particles
    int num_threads = 4;  // Default number of threads
    char *output_file = "/app/openmp.txt";
    char *summary_file = "/app/openmp_summary.txt";

    // Parse command line arguments
    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "-n") == 0 && i + 1 < argc) {
            n = atoi(argv[++i]);
        } else if (strcmp(argv[i], "-p") == 0 && i + 1 < argc) {
            num_threads = atoi(argv[++i]);
        } else if (strcmp(argv[i], "-o") == 0 && i + 1 < argc) {
            output_file = argv[++i];
        } else if (strcmp(argv[i], "-s") == 0 && i + 1 < argc) {
            summary_file = argv[++i];
        }
    }

    if (n <= 0) {
        fprintf(stderr, "Error: Number of particles (-n) must be specified and positive\n");
        return 1;
    }

    // Set number of threads
    omp_set_num_threads(num_threads);

    // Allocate particles
    Particle *particles = malloc(n * sizeof(Particle));
    if (!particles) {
        fprintf(stderr, "Error: Failed to allocate memory for particles\n");
        return 1;
    }

    // Initialize particles
    initialize_particles(particles, n);

    // Run simulation
    clock_t start = clock();

    // Simple simulation with fixed number of steps
    for (int step = 0; step < 100; step++) {
        compute_forces_openmp(particles, n, num_threads);
        update_positions(particles, n);
    }

    clock_t end = clock();
    double elapsed = ((double)(end - start)) / CLOCKS_PER_SEC;

    // Write positions to output file
    FILE *out_fp = fopen(output_file, "w");
    if (out_fp) {
        write_positions(out_fp, particles, n);
        fclose(out_fp);
    } else {
        fprintf(stderr, "Warning: Could not open output file %s\n", output_file);
    }

    // Write summary to summary file
    FILE *summary_fp = fopen(summary_file, "w");
    if (summary_fp) {
        fprintf(summary_fp, "%d %d %.6f\n", n, num_threads, elapsed);
        fclose(summary_fp);
    } else {
        fprintf(stderr, "Warning: Could not open summary file %s\n", summary_file);
    }

    // Calculate physics validation metrics
    double absmin = calculate_min_distance(particles, n);
    double absavg = calculate_avg_distance(particles, n);

    // Print results
    printf("n = %d, simulation time = %.6f seconds\n", n, elapsed);
    printf("threads = %d\n", num_threads);
    printf("absmin = %.6f\n", absmin);
    printf("absavg = %.6f\n", absavg);

    free(particles);
    return 0;
}
EOF
